function cleanScrapedContent(raw) {
  if (typeof raw !== 'string') return ''; // guard so a bad/missing item doesn't crash the node

  let text = raw;
  text = text.replace(/<[^>]+>/g, ' ');
  text = text.replace(/!\[[^\]]*\]\([^)]*\)/g, '');
  text = text.replace(/\[([^\]]*)\]\([^)]*\)/g, '$1');

  const noisePatterns = [
    /skip to content/i, /navigation menu/i, /^\*?\s*close$/i,
    /^\*?\s*login$/i, /^\*?\s*search$/i, /^\*?\s*cart$/i,
    /add to cart/i, /choose options/i, /sale price/i,
    /rated [\d.]+ out of 5 stars/i, /^\d+ reviews?$/i,
    /\(USD \$\)/, /sign up for (special offers|newsletter)/i,
    /^©/, /^\*?\s*best seller$/i, /^\*?\s*new$/i,
    /^\d+(\.\d+)?$/, /&nbsp;?/i, /accept cookies|we use cookies/i,
    /all rights reserved/i,
  ];

  const seen = new Set();
  const kept = [];

  for (const rawLine of text.split('\n')) {
    const line = rawLine.trim();
    if (!line) continue;
    if (noisePatterns.some(p => p.test(line))) continue;
    if (seen.has(line)) continue;
    seen.add(line);
    kept.push(line);
  }

  return kept.join('\n').replace(/[ \t]+/g, ' ').trim();
}

return $input.all().map(item => ({
  json: {
    ...item.json,
    chatInput: cleanScrapedContent(item.json.response.body),
  },
}));

const raw = $input.first().json.text; // adjust field name to match your chain's actual output key

// strip markdown fences if the model added them anyway
const cleaned = raw.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  // fallback shape so the workflow never breaks
  parsed = { script: [], hashtags: [], hooks: [], error: true, raw };
}

return [{ json: parsed }];

const raw = $json.data;

const match = raw.match(
  /event:\s*complete\s*data:\s*(\[[\s\S]*\])/m
);

let audioUrl = null;

if (match) {
  try {
    const files = JSON.parse(match[1]);
    audioUrl = files?.[0]?.url || null;
  } catch (err) {
    console.error(err);
  }
}

return [
  {
    json: {
      audioUrl
    }
  }
];
